\frac{S_{3n}}{S_n} &= \left(\frac{n}{3n-1}\right)^2 \Longleftrightarrow & \frac{9n^2}{2(\alpha+3n-1)} &= \frac{4n^2}{2(\alpha+n-1)} \\ &\Longrightarrow & 2\alpha+3n-1 &= \frac{12\alpha}{9}+6n-3\alpha\ \Longleftrightarrow & \frac{2}{3}\alpha - 18 &= 3n \Longleftrightarrow & \alpha = 27. \end{align*}
